class CustomActivation(nn.Module):
    """GELU activation function.

    GELU(x) = x * Phi(x) where Phi is the Gaussian CDF.
    Smooth, non-monotonic, allows small negative values.
    """

    def __init__(self):
        super().__init__()

    def forward(self, x):
        return F.gelu(x)
